const state={route:'home',quick:false,recording:false,answered:false,goal:0,roleAnswer:'',roleStep:0,roleInputMode:'voice',roleAnswers:[],roleTipOpen:false,roleVoice:'warm-man',roleVoiceOpen:false,dialogPanel:'',liveMode:false,bubbleMode:false,showTranslation:false,mistakeRevealed:false,roundIndex:2,interviewStage:-1,sessionIndex:0,interviewDraft:{jobPrompt:'我要面试 SpeakUp 产品经理',jobName:'SpeakUp 产品经理',jobDescription:'负责产品整体规划与迭代，结合用户需求、业务目标与市场趋势明确产品方向。',resumeHighlights:'4 年互联网产品经验，熟悉用户研究、原型设计、数据复盘与跨团队协作。',focusScope:'自我介绍、产品判断、终面',requirements:''}};
const S=document.getElementById('screen');
const esc=s=>String(s).replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]));
const topbar=(title,back='home',right='')=>`<div class="topbar"><button class="ghost-icon" data-route="${back}" aria-label="返回">‹</button><h2>${title}</h2>${right||'<span style="width:38px"></span>'}</div>`;
const steps=n=>`<div class="steps">${['输入职位','生成方案','确认面试官'].map((x,i)=>`<div class="step ${i+1===n?'active':''} ${i+1<n?'done':''}"><b>${i+1<n?'✓':i+1}</b>${x}</div>`).join('')}</div>`;
