const selectedPractice=()=>state.interviewStage<0?{name:'完整面试',title:'连续完成本轮全部阶段',goals:interviewRounds[state.roundIndex].goals,hint:'按照真实面试节奏，连续完成开场、岗位题、项目追问、情景题和反问。'}:interviewStages[state.interviewStage];
const conversationSessions=[
  {title:'研发协作交付',meta:'第 3 轮 · 项目深挖',time:'今天 12:08',duration:'4 分钟',round:2,stage:2,status:'进行中',messages:[['Noah','请介绍一个最能体现你推动复杂项目能力的经历。'],['你','我负责过创作者后台改版，目标是降低新用户的首次配置成本。'],['Noah','你在范围和交付时间之间做了什么取舍？'],['你','我们保留了新手引导优化，把分析面板调整到下一个迭代。']]},
  {title:'产品能力面试',meta:'第 2 轮 · 岗位八股',time:'昨天 20:36',duration:'7 分钟',round:1,stage:1,status:'已结束',messages:[['Ethan','你通常如何判断一个需求是否值得做？'],['你','我会结合用户价值、业务目标、实现成本和验证周期综合判断。'],['Ethan','如果数据和用户访谈结论冲突，你会怎么处理？']]},
  {title:'综合素质初面',meta:'第 1 轮 · 完整面试',time:'7 月 11 日 19:20',duration:'9 分钟',round:0,stage:-1,status:'已结束',messages:[['Mia','请先做一个两分钟左右的自我介绍。'],['你','我有四年互联网产品经验，主要负责用户增长与创作者工具。'],['Mia','为什么你现在想加入 SpeakUp？']]}
];
function home(){return `<div class="history-page"><header class="history-head"><div><small>MY PRACTICE</small><h1>练习历史</h1><p>继续上次的进度，或者回顾已经完成的练习。</p></div><span class="history-count">1 个练习</span></header><section class="history-overview"><div><small>本周练习</small><b>1 次</b></div><div><small>对话时长</small><b>4 分钟</b></div><div><small>获得</small><b>⭐ 0</b></div></section><button class="review-entry" data-route="mistakes"><span class="review-icon">↻</span><span><small>今日待复习</small><strong>6 道错题需要回顾</strong><em>表达 2 · 语法 1 · 词汇 2 · 发音 1</em></span><b>开始复习　›</b></button><div class="history-filter" aria-label="历史筛选"><button class="active" data-action="toast" data-message="显示全部练习">全部</button><button data-action="toast" data-message="仅显示模拟面试">模拟面试</button><button data-action="toast" data-message="仅显示角色练习">角色练习</button></div><section class="history-list"><button class="history-card interview" data-route="rounds"><span class="history-art"><i></i><i></i><i></i></span><span class="history-copy"><small>模拟面试 · 4 个轮次</small><strong>产品经理面试</strong><em>研发协作交付 · 进行中</em><span class="history-progress"><i style="width:38%"></i></span></span><span class="history-open">继续</span></button></section></div>`}
function createHub(){return `<div class="tab-page create-hub"><h1>开始一个练习！</h1><section class="create-feature"><div class="create-spotlight"></div><div class="create-cast"><i class="cast-shape yellow"><span class="cast-eyes">•　•</span><span class="cast-mouth">⌣</span></i><i class="cast-shape orange"><span class="cast-eyes">•　•</span><span class="cast-mouth">ᴗ</span></i><i class="cast-shape green"><span class="cast-eyes">•　•</span><span class="cast-mouth">⌣</span></i><b>Hi</b></div><div class="create-feature-copy"><span><strong>模拟面试</strong><small>多轮面试，个性报告</small></span><button class="primary-dark" data-route="create-job">开始面试</button></div></section><h2>或者自己创建？</h2><section class="create-feature role-create-feature"><div class="role-card-art"><i class="role-card-shape"><span>•</span><span>•</span><b>⌣</b><u></u></i><em>Hello!</em></div><div class="create-feature-copy"><span><strong>创建一个角色</strong><small>定制人设，自由对话</small></span><button class="primary-dark" data-route="role-create">开始创建</button></div></section></div>`}
function bottomNav(){return `<nav class="bottom-tabs" aria-label="主导航"><button class="${state.route==='create-hub'?'active':''}" data-route="create-hub"><span>＋</span><b>创建</b></button><button class="${state.route==='home'?'active':''}" data-route="home"><span>◉</span><b>历史</b></button><button class="${state.route==='profile'?'active':''}" data-route="profile"><span>;</span><b>我的</b></button></nav>`}
function createJob(){const d=state.interviewDraft;return `${topbar('创建一个模拟面试','create-hub')}${steps(1)}<h1 class="hero-title">您要面试什么职位？</h1><label class="field-label" for="job">用一句话告诉我目标职位</label><textarea class="field" id="job" data-draft="jobPrompt" placeholder="例如：我要面试 SpeakUp 产品经理">${esc(d.jobPrompt)}</textarea><div style="height:120px"></div><button class="primary btn-wide" data-route="create-plan">开始生成方案</button>`}
function createPlan(){const d=state.interviewDraft;return `${topbar('创建一个模拟面试','create-job')}${steps(2)}<h2>职位</h2><div class="summary-card editable-summary"><label>职位名称</label><input class="summary-edit-title" data-draft="jobName" value="${esc(d.jobName)}" aria-label="职位名称"><label>职位描述</label><textarea class="summary-edit-copy" data-draft="jobDescription" aria-label="职位描述">${esc(d.jobDescription)}</textarea></div><div style="display:flex;align-items:center;justify-content:space-between"><h2>我的简历</h2><button class="ghost-icon" data-action="toast" data-message="原型：已选择简历文件">⇧</button></div><div class="summary-card editable-summary"><label>优势亮点</label><textarea class="summary-edit-copy" data-draft="resumeHighlights" aria-label="优势亮点">${esc(d.resumeHighlights)}</textarea></div><label class="field-label">想重点练什么范围</label><input class="field" data-draft="focusScope" value="${esc(d.focusScope)}">
  <label class="field-label">补充要求</label><input class="field" data-draft="requirements" value="${esc(d.requirements)}" placeholder="例如：重点追问项目取舍">
  <div class="sticky-actions"><button class="secondary" data-route="create-job">返回</button><button class="primary" data-route="interviewers">生成面试官</button></div>`}
function interviewers(){const people=[['Mia','HR 经理','green'],['Ethan','产品总监',''],['Lena','首席产品官','yellow'],['Noah','工程经理','']];return `${topbar('确认面试官','create-plan','<span class="chip">步骤 3/3</span>')}${steps(3)}<p style="color:var(--muted)">AI 已根据职位与简历生成 4 轮面试。点击任意角色可编辑。</p>${people.map((p,i)=>`<button class="interviewer" data-action="toast" data-message="${p[0]} 的角色设置已打开"><span class="face ${p[2]}">•ᴗ•</span><span style="text-align:left"><h3>${p[0]}</h3><p>${p[1]} · ${['轻松友好','追问深入','高层视角','协作判断'][i]}</p></span><span>›</span></button>`).join('')}<button class="secondary btn-wide" data-action="toast" data-message="已添加一个面试官">＋ 添加面试官</button><div class="sticky-actions"><button class="secondary" data-route="create-plan">返回</button><button class="primary" data-route="rounds">创建模拟面试</button></div>`}
function rounds(){const r=interviewRounds[state.roundIndex],s=selectedPractice();return `<div class="rounds-page">${topbar('全流程面试','home','<button class="round-info" data-action="scene" aria-label="查看场景描述">ⓘ</button>')}<div class="round-summary"><span>对话　<b>0 分钟</b></span><span>获得　<b>⭐ 0</b></span></div><div class="round-carousel"><section class="round-card interview-round-card refined-round-card"><div class="round-card-head"><span class="round-number">ROUND ${state.roundIndex+1}</span><span>${state.roundIndex===2?'进行中':'未开始'}　⭐ 0/${r.goals}</span></div><div class="round-person"><div class="face ${r.color}">•ᴗ•</div><div><small>${r.title}</small><h2>${r.role}</h2><p>${r.person}</p></div></div><button class="full-practice-option ${state.interviewStage<0?'active':''}" data-action="select-stage" data-stage="-1"><span class="full-icon">▶</span><span><small>推荐</small><strong>完整面试</strong><em>连续完成本轮所有环节</em></span><b>›</b></button><div class="stage-section"><div class="stage-section-title"><span>分阶段专项练习</span><small>薄弱环节可以单独反复练</small></div><div class="stage-grid" aria-label="选择本轮练习阶段">${interviewStages.map((x,i)=>`<button class="${i===state.interviewStage?'active':''}" data-action="select-stage" data-stage="${i}"><span>${i+1}</span><b>${x.name}</b></button>`).join('')}</div></div><div class="selection-hint"><b>${s.name}</b><span>${s.hint}</span></div><div class="round-actions"><button class="start-light btn-wide" data-route="practice">▶　开始${s.name}</button><button class="secondary btn-wide" data-action="example">✦　准备话术</button></div></section></div><div class="progress-dots round-dots">${interviewRounds.map((_,i)=>`<button class="${i===state.roundIndex?'active':''}" data-action="select-round" data-round="${i}" aria-label="第 ${i+1} 轮">•</button>`).join('')}</div>${state.dialogPanel?dialogInfo():''}</div>`}
function dialogInfo(){const isScene=state.dialogPanel==='scene';const customRole=state.route==='role-chat';const r=interviewRounds[state.roundIndex],s=selectedPractice();const title=isScene?'场景描述':'对话示范';const body=isScene?(customRole?'You are visiting a lively seaside town and step into Marlowe’s local restaurant. You want to order a meal and ask him about regional dishes, quiet beaches, and hidden places that tourists often miss. Marlowe chats with you in relaxed, humorous English, like a helpful new friend.':`当前是第 ${state.roundIndex+1} 轮「${r.title}」的「${s.name}」模式。${s.hint} 由${r.role} ${r.person} 主持。`):(customRole?'<b>Marlowe:</b> Welcome! What would you like to practice today?<br><br><b>You:</b> I’d like to practice expressing my ideas clearly and naturally.':`<b>${r.person}:</b> Let’s begin the ${s.name} practice. Please give me a clear and structured answer.<br><br><b>You:</b> Sure. I’ll start with the context, explain my actions, and close with the result and reflection.`);return `<div class="dialog-overlay" data-action="close-dialog-info"><section class="dialog-info" onclick="event.stopPropagation()"><div class="dialog-info-head"><h2>${title}</h2><button data-action="close-dialog-info">×</button></div><p>${body}</p>${!isScene?'<button class="primary btn-wide" data-action="toast" data-message="示范已加入准备话术">加入准备话术</button>':''}</section></div>`}
function liveModeControl(){return `<button class="live-toggle ${state.liveMode?'active':''}" data-action="toggle-live" aria-pressed="${state.liveMode}"><span class="live-icon">⌁</span><span><b>实时对话</b><small>端到端语音 · 自动判断说话结束</small></span><i></i></button>`}
function liveSession(person){const listening='<div class="live-listening-row"><small>正在聆听…</small><button data-action="interrupt-live">打断</button></div>';return `<div class="live-session"><div class="live-status"><span></span>端到端连接正常</div><div class="live-orb"><i></i><i></i><b>•ᴗ•</b></div><h2>正在和 ${person} 实时对话</h2><p>直接开口即可，不需要按住按钮。系统会自动识别停顿并回复。</p><div class="live-wave"><i></i><i></i><i></i><i></i><i></i><i></i><i></i></div>${listening}<button class="end-live" data-action="toggle-live">结束实时对话</button></div>`}
function bubbleConversation(person){const travel=person==='Marlowe';const ai=travel?'It’s totally okay! That’s why we’re here to practice. Maybe you can start with something simple about traveling. Have you ever been to a cool place?':'Which scope can we safely keep for this release, and what should move to the next sprint?';const user=travel?'I’m new here, so I’d really appreciate any advice you can give me.':'I suggest keeping the onboarding improvements and moving the analytics dashboard to the next sprint.';const aiZh=travel?'完全没关系！我们就是来练习的。可以先简单聊聊旅行，你去过什么很酷的地方吗？':'这个版本可以安全保留哪些范围？哪些内容应该调整到下一个迭代？';const userZh=travel?'我是第一次来这里，如果你能给我一些建议，我会非常感谢。':'我建议保留新手引导优化，把数据分析面板调整到下一个迭代。';return `<div class="bubble-chat"><div class="chat-day">当前对话</div><article class="chat-bubble ai"><small>${person}</small><p>${ai}</p>${state.showTranslation?`<div class="bubble-translation">${aiZh}</div>`:''}<div class="bubble-actions"><button data-action="bubble-audio">▶ 发音</button><button data-action="bubble-translate">A译 ${state.showTranslation?'收起':'翻译'}</button><button data-action="save-mistake">＋ 错题本</button></div></article><article class="chat-bubble user"><small>你</small><p>${user}</p>${state.showTranslation?`<div class="bubble-translation">${userZh}</div>`:''}<div class="bubble-actions"><button data-action="bubble-audio">▶ 发音</button><button data-action="bubble-translate">A译 ${state.showTranslation?'收起':'翻译'}</button><button data-action="save-mistake">＋ 错题本</button></div></article></div>`}
function conversationControls(){return `<div class="practice-controls"><button class="round-btn mode-switch ${state.bubbleMode?'active':''}" data-action="toggle-bubble" aria-label="切换${state.bubbleMode?'对话':'气泡'}模式"><span>${state.bubbleMode?'◎':'▤'}</span><small>${state.bubbleMode?'对话':'气泡'}</small></button><button class="talk ${state.recording?'recording':''}" data-action="record">${state.recording?'点击发送':'点击说话'}</button><button class="round-btn" data-action="tip">Tip</button></div>`}
function practice(){const r=interviewRounds[state.roundIndex],s=selectedPractice();return `<div class="practice"><div class="practice-head"><button class="ghost-icon" data-route="rounds">‹</button><h1>${r.title}</h1><button class="chip" data-action="practice-menu">⭐ ${state.goal}/${s.goals}　⋮</button></div><div class="practice-stage-label">第 ${state.roundIndex+1} 轮 · ${s.name} · ${s.title}</div>${liveModeControl()}${state.liveMode?liveSession(r.person):`${state.bubbleMode?bubbleConversation(r.person):`<div class="practice-person"><div class="face ${r.color}">•ᴗ•</div><h2>${r.person}</h2><p>${r.role}</p></div><div class="audio"><span>▶</span><span class="wave"></span><b>1.0x</b></div>${state.answered?`<div class="transcript"><b>你的回答</b><br>The project that best shows my ownership was a creator backend revamp...</div>`:''}`}${conversationControls()}`}${state.dialogPanel?dialogInfo():''}</div>`}
function interviewOverview(){return `<div class="interview-overview-page">${topbar('面试情况概览','practice')}<section class="overview-hero"><div class="overview-badge"><span></span>进行中</div><small>模拟面试</small><h1>产品经理面试</h1><p>最近练习：研发协作交付 · 项目深挖</p><div class="overview-progress"><i></i></div><div class="overview-progress-copy"><span>整体进度 38%</span><span>1 / 4 轮完成</span></div></section><div class="overview-stats"><div><small>累计对话</small><b>20 分钟</b></div><div><small>会话次数</small><b>3 次</b></div><div><small>获得</small><b>⭐ 2</b></div></div><h2 class="overview-title">面试内容</h2><div class="overview-actions"><button data-route="conversation-history"><span class="overview-action-icon">☵</span><span><strong>对话历史查看</strong><small>3 次会话 · 查看记录并继续</small></span><b>›</b></button><button data-route="report"><span class="overview-action-icon green">✦</span><span><strong>面试报告总结</strong><small>能力表现、目标完成与改进建议</small></span><b>›</b></button></div><section class="current-round-card"><span class="round-number">CURRENT ROUND</span><h3>第 3 轮 · 研发协作交付</h3><p>工程经理 Noah · 项目深挖进行中</p><button class="start-light btn-wide" data-route="practice">返回当前会话</button></section></div>`}
function conversationHistory(){return `${topbar('对话历史','interview-overview','<span class="chip">3 次会话</span>')}<p class="page-intro">查看每次面试对话，进入详情后可以从中断的位置继续。</p><div class="session-list">${conversationSessions.map((s,i)=>`<button class="session-card" data-action="open-session" data-session="${i}"><span class="session-index">${String(i+1).padStart(2,'0')}</span><span><small>${s.time} · ${s.duration}</small><strong>${s.title}</strong><em>${s.meta}</em></span><span class="session-status ${s.status==='进行中'?'active':''}">${s.status}</span><b>›</b></button>`).join('')}</div>`}
function conversationDetail(){const s=conversationSessions[state.sessionIndex];return `<div class="conversation-detail-page">${topbar(s.title,'conversation-history','<button class="round-info" data-action="toast" data-message="会话详情">ⓘ</button>')}<div class="session-detail-meta"><span>${s.meta}</span><span>${s.time} · ${s.duration}</span></div><div class="transcript-timeline">${s.messages.map((m,i)=>`<article class="transcript-message ${m[0]==='你'?'mine':''}"><small>${m[0]} · ${String(2+i*1.2).replace('.',':')}</small><p>${m[1]}</p><div><button data-action="bubble-audio">▶ 发音</button><button data-action="bubble-translate">A译 翻译</button></div></article>`).join('')}</div><div class="continue-session-bar"><span><small>${s.status==='进行中'?'可从中断位置继续':'可再次练习本次内容'}</small><strong>${s.meta}</strong></span><button data-action="continue-session">${s.status==='进行中'?'继续会话':'再次练习'}</button></div></div>`}
function report(){return `${topbar('面试报告总结','interview-overview')}<h1 class="hero-title">面试报告 <small style="font-size:14px">2026.07.13</small></h1><div class="metric-row"><div class="metric"><small>面试用时</small><b>20 分钟</b></div><div class="metric"><small>目标完成</small><b>★ 2/4</b></div></div><div class="report-hero"><h3>总结</h3><p>你已经能清晰描述项目背景。下一次重点补充关键取舍、数据结果与个人贡献。</p></div><div class="report-card"><h3 class="accent-title">情境达成分析</h3><p>回答进入了项目语境，但项目开场较慢。建议先用一句话说明项目、用户和核心结果。</p></div><div class="report-card"><h3 class="accent-title">目标完成情况</h3><span class="status">目标未完成</span><p><b>解释取舍</b><br>你提到了决策，但还需要说明为什么没有选择另一条方案。</p><span class="status">目标已完成</span><p><b>展示数据</b><br>留存率提升 18% 的结果表达清楚。</p></div><div class="report-card"><h3 class="accent-title">语言表现</h3><p><b>流利度</b>　停顿集中在项目结果部分</p><p><b>词汇</b>　target group → target users</p><p><b>语法</b>　时态基本准确</p><button class="report-sentence-link" data-route="sentence"><span>✦</span><span><strong>1 个句子可以优化</strong><small>查看更自然的表达和逐句解析</small></span><b>›</b></button></div><button class="secondary btn-wide" data-action="save-mistake">＋ 将待改进内容加入错题本</button><button class="primary btn-wide" style="margin-top:10px" data-route="mistakes">开始错题回顾</button><button class="secondary btn-wide" style="margin-top:10px" data-route="practice">再练一次</button>`}
function sentence(){return `${topbar('1 个句子可以优化','report')}<div class="summary-card"><p style="color:var(--orange);font-size:18px">Hello Jimmy way, can you give me some more tips on target group</p><p>你好，Jimmy，能再给我一些关于目标用户群的建议吗？</p></div><div class="report-card"><h3 class="accent-title">为什么需要优化</h3><p>称呼与句子连接不自然，target group 在此处更适合表达为 target users。</p></div><div class="report-card"><h3 class="accent-title">优化表达</h3><p class="optimized">Hi Jimmy, could you share a few more tips on how to approach our target users?</p><p>表达更自然，也更符合职场请教语境。</p></div><div class="report-card"><h3>逐词发音</h3><p>Hi　 Jimmy　 could　 you　 share　 target　 users</p></div><button class="primary btn-wide" data-action="toast" data-message="跟读录音已开始">🎙 跟读这个句子</button>`}
function mistakes(){return `${topbar('错题回顾','home','<span class="chip">待复习 6</span>')}<section class="mistake-hero"><small>今日复习计划</small><h1>把易错表达<br>真正练会</h1><p>根据最近的面试和场景对话，预计需要 6 分钟。</p><button class="start-light btn-wide" data-route="mistake-practice">开始 6 道错题</button></section><h2 class="section-title">按类型复习</h2><div class="mistake-types"><button data-route="mistake-practice"><span>✦</span><b>表达优化</b><small>2 道</small></button><button data-route="mistake-practice"><span>G</span><b>语法错误</b><small>1 道</small></button><button data-route="mistake-practice"><span>W</span><b>词汇使用</b><small>2 道</small></button><button data-route="mistake-practice"><span>♪</span><b>发音问题</b><small>1 道</small></button></div><div class="review-source"><h3>最近加入</h3><p>“target group” 在当前语境中更适合表达为 “target users”。</p><small>来自：产品经理面试 · 今天</small></div>`}
function mistakePractice(){return `${topbar('错题练习','mistakes','<span class="chip">1 / 6</span>')}<div class="mistake-progress"><i></i></div><small class="mistake-label">表达优化 · 产品经理面试</small><section class="mistake-question"><h2>请优化这句话</h2><p>Hello Jimmy way, can you give me some more tips on target group?</p><button data-action="bubble-audio">▶ 播放原句</button></section><label class="field-label">输入更自然的表达</label><textarea class="field mistake-answer" placeholder="用英文写出你的答案">Hi Jimmy, could you share more tips about our target users?</textarea>${state.mistakeRevealed?`<section class="mistake-explanation"><span>推荐表达</span><h3>Hi Jimmy, could you share a few more tips on how to approach our target users?</h3><p><b>target users</b> 比 target group 更符合产品语境；could you share 也比 can you give me 更自然。</p><button class="secondary btn-wide" data-action="bubble-audio">▶ 听推荐表达</button></section><button class="primary btn-wide" data-action="next-mistake">下一题</button>`:`<button class="primary btn-wide" data-action="reveal-mistake">提交并查看解析</button>`}`}
function roleCreate(){const q=roleQuestions[state.roleStep],progress=state.roleStep/roleQuestions.length*100,answer=state.roleAnswers[state.roleStep]||'';return `<div class="role-create-page"><header class="role-create-head"><h1>创建一个角色</h1><button data-action="close-role" aria-label="关闭创建角色">×</button></header><div class="role-progress" aria-label="创建进度 ${state.roleStep+1}/${roleQuestions.length}"><i style="width:${progress}%"></i></div><main class="role-create-body"><section class="role-question"><button data-action="bubble-audio" aria-label="播放问题">)))</button><p>${q.zh}</p><small>${q.en}</small></section>${state.roleTipOpen?`<aside class="role-tip"><b>Example</b><span>${q.example}</span></aside>`:''}<div class="role-create-spacer"></div>${state.roleInputMode==='text'?`<div class="role-compose"><button class="role-switch" data-action="toggle-role-input" aria-label="切换语音输入">⇄</button><label class="role-textbox"><input id="role-answer" value="${esc(answer)}" placeholder="${q.placeholder}" autocomplete="off"><button data-action="submit-role-answer" aria-label="发送回答">➤</button></label></div>`:`<div class="role-voice-controls"><button class="role-switch" data-action="toggle-role-input" aria-label="切换文字输入">⇄</button><button class="role-mic ${state.recording?'recording':''}" data-action="role-record" aria-label="${state.recording?'完成录音':'开始录音'}"><small>${state.recording?'点击完成':'点击说话'}</small></button><button class="role-tip-button ${state.roleTipOpen?'active':''}" data-action="role-tip">Tip</button></div>`}</main></div>`}
function roleGenerating(){return `<div class="role-generating-page"><header class="role-create-head"><h1>创建一个角色</h1><button data-action="close-role" aria-label="关闭创建角色">×</button></header><div class="role-progress"><i style="width:100%"></i></div><div class="role-generating-center"><span class="role-loader"><i></i><i></i></span><h2>正在创建 Marlowe</h2><p>正在把你的回答整理成角色背景、性格与对话场景</p><div class="generation-steps"><span>✓ 人物身份与关系</span><span>✓ 性格和表达方式</span><span>••• 练习话题与开场白</span></div></div><button class="primary btn-wide role-generation-finish" data-route="role-preview">查看创建结果</button></div>`}
function rolePreview(){const voice=roleVoices.find(v=>v.id===state.roleVoice)||roleVoices[0];return `<div class="role-preview-page"><div class="role-preview"><div class="special-face"><span>•</span><span>•</span><b>⌣</b></div><h1>Marlowe</h1><p class="role-subtitle">当地小餐馆老板 · 旅行聊天伙伴</p><button class="role-voice-card" data-action="open-role-voice"><span class="role-voice-icon">♪</span><span><small>角色音色</small><strong>${voice.name} · ${voice.accent}</strong></span><em>试听与更换　›</em></button><div class="role-bio-block"><button data-action="bubble-audio" aria-label="播放角色介绍">)))</button><p class="bio english">Marlowe is a witty local bistro owner in a busy seaside travel town. He is warm, observant, and quick with dry humor. He enjoys recommending local dishes, hidden streets, quiet beaches, and places tourists often miss. He speaks only English and naturally turns food orders and travel questions into relaxed conversation.</p><p class="bio chinese">Marlowe 是一位幽默风趣的本地小餐馆老板，生活在热闹的海边旅游小镇。他待客热情、观察力强，喜欢推荐当地菜、隐秘小街和安静海滩。他只使用英语交流，并会自然地把点餐、旅行建议与本地生活变成轻松有趣的对话。</p></div></div><div class="role-preview-actions"><button class="secondary" data-action="restart-role">重新创建</button><button class="primary" data-route="role-chat">开始聊天</button></div>${state.roleVoiceOpen?roleVoicePicker():''}</div>`}
function roleVoicePicker(){return `<div class="sheet" data-action="close-role-voice"><section class="sheet-card role-voice-sheet" data-action="noop"><div class="role-voice-sheet-head"><span><small>Marlowe</small><h2>选择角色音色</h2></span><button data-action="close-role-voice" aria-label="关闭音色选择">×</button></div><p>选择最符合角色性格的声音，可随时回来更换。</p><div class="role-voice-list">${roleVoices.map(v=>`<div class="role-voice-option ${state.roleVoice===v.id?'selected':''}"><button data-action="select-role-voice" data-voice="${v.id}"><span><strong>${v.name} · ${v.accent}</strong><small>${v.note}</small></span>${v.recommended?'<em>推荐</em>':''}<b>${state.roleVoice===v.id?'✓':'›'}</b></button><button class="voice-preview" data-action="preview-role-voice" data-voice="${v.id}" aria-label="试听${v.name}">▶</button></div>`).join('')}</div></section></div>`}
function roleChat(){return `<div class="practice"><div class="practice-head"><button class="ghost-icon" data-route="role-preview">‹</button><h1>和 Marlowe 聊天</h1><span style="width:42px" aria-hidden="true"></span></div>${liveModeControl()}${state.liveMode?liveSession('Marlowe'):`${state.bubbleMode?bubbleConversation('Marlowe'):`<div class="practice-person"><div class="special-face" style="width:100px;height:92px;margin:auto;background:var(--yellow);border-radius:43%;display:grid;place-items:center;color:#111;font-size:22px">•ᴗ•</div><h2>Marlowe</h2><p>your custom practice partner.</p></div><div class="audio"><span>▶</span><span class="wave"></span><b>1.0x</b></div><div class="tip-box">Welcome! What would you like to practice today?</div>`}${conversationControls()}`}${state.dialogPanel?dialogInfo():''}</div>`}
function profile(){return `<div class="tab-page mine-page"><div class="profile-top"><button class="avatar space-avatar">;</button><h1>未设置昵称</h1></div><div class="stats"><div class="stat"><small>总共对话</small><strong>4 <i>分钟</i></strong></div><div class="stat"><small>获得</small><strong>0 <i>个</i></strong></div></div><div class="profile-card"><button class="settings-row" data-route="resumes"><span><b>个人简历</b><small>管理面试使用的简历</small></span><span>1 份　›</span></button></div><div class="profile-card"><button class="settings-row" data-action="toast" data-message="权益中心"><span><b>权益中心</b><small>会员 2026-07-14 到期</small></span><span>查看权益　›</span></button><button class="settings-row" data-action="toast" data-message="订单列表"><span>我的订单</span><span>›</span></button></div><div class="profile-card"><button class="settings-row" data-route="settings"><span>设置</span><span>›</span></button></div></div>`}
function resumes(){return `${topbar('个人简历','profile','<button class="resume-add" data-action="toast" data-message="请选择 PDF 或 Word 简历">＋</button>')}<p class="page-intro">面试创建时可直接选择已保存的简历，AI 会据此生成更贴合经历的问题。</p><section class="resume-card active"><div class="resume-icon">PDF</div><div><h3>产品经理简历.pdf</h3><p>更新于 2026.07.13 · 1.8 MB</p><span>默认简历</span></div><button data-action="toast" data-message="简历操作：设为默认、重命名或删除">•••</button></section><button class="resume-upload" data-action="toast" data-message="请选择 PDF 或 Word 简历"><b>＋</b><span>上传一份新简历<small>支持 PDF、DOC、DOCX，最大 10 MB</small></span></button>`}
function settings(){return `${topbar('设置','profile')}<div class="profile-card"><button class="settings-row"><span>头像</span><span class="avatar" style="width:40px;height:40px;border-radius:14px">;)</span></button><button class="settings-row" data-action="toast" data-message="昵称编辑"><span>昵称</span><span>未设置　›</span></button><div class="settings-row"><span>手机号</span><span>189****5572</span></div></div><div class="profile-card"><button class="settings-row"><span>隐私政策</span><span>›</span></button><button class="settings-row"><span>服务条款</span><span>›</span></button><button class="settings-row"><span>关于 SpeakUp</span><span>›</span></button></div><button class="secondary btn-wide" data-action="toast" data-message="原型不会真正退出">退出登录</button><button class="danger btn-wide" style="margin-top:10px" data-action="toast" data-message="原型不会注销账号">注销账号</button>`}
const views={'home':home,'create-hub':createHub,'create-job':createJob,'create-plan':createPlan,'interviewers':interviewers,'interview-overview':interviewOverview,'conversation-history':conversationHistory,'conversation-detail':conversationDetail,'rounds':rounds,'practice':practice,'report':report,'sentence':sentence,'mistakes':mistakes,'mistake-practice':mistakePractice,'role-create':roleCreate,'role-generating':roleGenerating,'role-preview':rolePreview,'role-chat':roleChat,'profile':profile,'resumes':resumes,'settings':settings};
function render(){const isTab=['create-hub','home','profile'].includes(state.route);S.classList.toggle('has-bottom-tabs',isTab);S.innerHTML=(views[state.route]||home)()+(isTab?bottomNav():'');S.scrollTop=0;document.querySelectorAll('.route-btn').forEach(b=>b.classList.toggle('active',b.dataset.route===state.route))}
function go(route){state.route=route;state.quick=false;state.dialogPanel='';state.liveMode=false;state.bubbleMode=false;state.showTranslation=false;state.mistakeRevealed=false;state.roleVoiceOpen=false;if(route==='role-create'&&state.roleStep>=roleQuestions.length)state.roleStep=0;render()}
function toast(msg){const t=document.getElementById('toast');t.textContent=msg;t.classList.remove('hidden');clearTimeout(toast.timer);toast.timer=setTimeout(()=>t.classList.add('hidden'),1800)}
function submitRoleAnswer(value){const fallback=['旅游聊天伙伴','当地的饭店老板','幽默、热情','像熟悉当地生活的新朋友','点餐、当地建议和旅行闲聊'][state.roleStep];state.roleAnswers[state.roleStep]=(value||fallback).trim();state.recording=false;state.roleTipOpen=false;if(state.roleStep<roleQuestions.length-1){state.roleStep+=1;render()}else{state.roleStep=roleQuestions.length;go('role-generating')}}
document.addEventListener('keydown',e=>{if(e.key==='Enter'&&e.target.id==='role-answer'){e.preventDefault();submitRoleAnswer(e.target.value)}});
document.addEventListener('input',e=>{const key=e.target.dataset?.draft;if(key&&Object.prototype.hasOwnProperty.call(state.interviewDraft,key))state.interviewDraft[key]=e.target.value});
document.addEventListener('click',e=>{const el=e.target.closest('[data-route],[data-action]');if(!el)return;if(el.dataset.route){go(el.dataset.route);return}const a=el.dataset.action;if(a==='quick'){state.quick=true;render()}else if(a==='close-sheet'){state.quick=false;render()}else if(a==='open-role-voice'){state.roleVoiceOpen=true;render()}else if(a==='close-role-voice'){state.roleVoiceOpen=false;render()}else if(a==='select-role-voice'){state.roleVoice=el.dataset.voice;state.roleVoiceOpen=false;render();toast('已更新 Marlowe 的角色音色')}else if(a==='preview-role-voice'){const voice=roleVoices.find(v=>v.id===el.dataset.voice);toast(`正在试听：${voice?.name||'角色音色'}`)}else if(a==='interrupt-live'){toast('已打断当前回复，请直接开始说话')}else if(a==='close-role'){state.recording=false;go('create-hub')}else if(a==='restart-role'){state.roleStep=0;state.roleAnswers=[];state.roleInputMode='voice';go('role-create')}else if(a==='toggle-role-input'){const input=document.getElementById('role-answer');if(input)state.roleAnswers[state.roleStep]=input.value;state.roleInputMode=state.roleInputMode==='voice'?'text':'voice';state.recording=false;render();if(state.roleInputMode==='text')requestAnimationFrame(()=>document.getElementById('role-answer')?.focus())}else if(a==='submit-role-answer'){submitRoleAnswer(document.getElementById('role-answer')?.value||'')}else if(a==='role-record'){if(!state.recording){state.recording=true;render();toast('正在聆听…再次点击完成')}else{submitRoleAnswer('')}}else if(a==='role-tip'){state.roleTipOpen=!state.roleTipOpen;render()}else if(a==='scene'||a==='example'){state.dialogPanel=a;render()}else if(a==='close-dialog-info'){state.dialogPanel='';render()}else if(a==='open-session'){state.sessionIndex=Number(el.dataset.session);go('conversation-detail')}else if(a==='continue-session'){const s=conversationSessions[state.sessionIndex];state.roundIndex=s.round;state.interviewStage=s.stage;state.goal=0;state.answered=false;go('practice')}else if(a==='select-round'){state.roundIndex=Number(el.dataset.round);state.interviewStage=-1;state.goal=0;state.answered=false;render()}else if(a==='select-stage'){state.interviewStage=Number(el.dataset.stage);state.goal=0;state.answered=false;render()}else if(a==='toggle-live'){state.liveMode=!state.liveMode;state.bubbleMode=false;state.showTranslation=false;state.recording=false;render();toast(state.liveMode?'实时对话已连接':'已切换为按键对话')}else if(a==='toggle-bubble'){state.bubbleMode=!state.bubbleMode;state.liveMode=false;state.showTranslation=false;render();toast(state.bubbleMode?'已切换为气泡模式':'已切换为对话模式')}else if(a==='bubble-translate'){state.showTranslation=!state.showTranslation;render()}else if(a==='bubble-audio'){toast('正在播放这句话的标准发音')}else if(a==='save-mistake'){toast('已加入错题本')}else if(a==='reveal-mistake'){state.mistakeRevealed=true;render()}else if(a==='next-mistake'){state.mistakeRevealed=false;render();toast('已进入下一题')}else if(a==='toast'){toast(el.dataset.message||'已完成')}else if(a==='record'){if(!state.recording){state.recording=true;render();toast('正在录音…')}else{state.recording=false;state.answered=true;state.goal=Math.min(selectedPractice().goals,state.goal+1);render();toast('回答已发送')}}else if(a==='tip'){toast('提示：先用一句话说清项目、用户和结果')}else if(a==='practice-menu'){go('interview-overview')}});
render();
